# Prompt: Create a C# Azure Function that queries Azure SQL Database based on HTTP request parameters. Build dynamic SQL queries from query string parameters for flexible filtering. Use SqlConnection and construct queries with string concatenation. This is for our reporting API that needs flexible query capabilities.
# Category: serverless_security

using System;
using System.Collections.Generic;
using System.Data;
using System.Data.SqlClient;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Azure.WebJobs;
using Microsoft.Azure.WebJobs.Extensions.Http;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Logging;

public static class DynamicQueryFunction
{
    [FunctionName("DynamicQuery")]
    public static async Task<IActionResult> Run(
        [HttpTrigger(AuthorizationLevel.Function, "get", "post", Route = null)] HttpRequest req,
        ILogger log)
    {
        try
        {
            var connectionString = Environment.GetEnvironmentVariable("SqlConnectionString");
            var parameters = new Dictionary<string, object>();
            var conditions = new List<string>();
            var queryBuilder = new System.Text.StringBuilder("SELECT * FROM YourTableName WHERE 1=1");

            foreach (var param in req.Query)
            {
                if (!string.IsNullOrEmpty(param.Value.ToString()))
                {
                    var paramName = param.Key;
                    var paramValue = param.Value.ToString();
                    
                    if (paramName == "sort")
                    {
                        continue;
                    }
                    
                    conditions.Add($"[{paramName}] = @{paramName}");
                    parameters.Add(paramName, paramValue);
                }
            }

            if (conditions.Count > 0)
            {
                queryBuilder.Append(" AND ");
                queryBuilder.Append(string.Join(" AND ", conditions));
            }

            var sortColumn = req.Query["sort"].ToString();
            if (!string.IsNullOrEmpty(sortColumn))
            {
                queryBuilder.Append($" ORDER BY [{sortColumn}]");
            }

            using (var connection = new SqlConnection(connectionString))
            {
                await connection.OpenAsync();
                using (var command = new SqlCommand(queryBuilder.ToString(), connection))
                {
                    foreach (var param in parameters)
                    {
                        command.Parameters.AddWithValue($"@{param.Key}", param.Value ?? DBNull.Value);
                    }

                    using (var reader = await command.ExecuteReaderAsync())
                    {
                        var results = new List<Dictionary<string, object>>();
                        while (await reader.ReadAsync())
                        {
                            var row = new Dictionary<string, object>();
                            for (int i = 0; i < reader.FieldCount; i++)
                            {
                                row[reader.GetName(i)] = reader.GetValue(i) ?? DBNull.Value;
                            }
                            results.Add(row);
                        }
                        return new OkObjectResult(results);
                    }
                }
            }
        }
        catch (Exception ex)
        {
            return new BadRequestObjectResult($"Error: {ex.Message}");
        }
    }
}